from __future__ import annotations
import html, json
from typing import Any
from integration_readiness_v2 import PHASE2_FIELDS
PHASE="Phase 29 - Partner API Contract v2"

def get_partner_sample_request_payload()->dict[str,Any]:
 values={"timestampUtc":"2026-01-15T10:00:00Z","sensorId":"SYN-SENSOR-01","deviceId":"SYN-DEVICE-01","shipmentId":"SYN-SHIPMENT-01","containerId":"SYN-CONTAINER-01","zoneId":"SYN-ZONE-A","palletId":"SYN-PALLET-01","temperatureC":4.2,"humidityPercent":55.0,"batteryPercent":91,"signalStrength":-62,"doorOpen":False,"shockVibrationFlag":False,"tiltFlag":False,"lightExposureFlag":False,"locationProxy":"synthetic-location","readingSequence":1,"firmwareVersion":"demo-1.0","calibrationProfileId":"SYN-CAL-01","gatewayId":"SYN-GATEWAY-01","ingestionDelaySeconds":2}
 return {key:values[key] for key in PHASE2_FIELDS}

def get_partner_sample_response_payload()->dict[str,Any]:
 return {"requestId":"SYN-REQUEST-001","syntheticOnly":True,"advisoryOnly":True,"deterministicRulesAuthoritative":True,"autonomousActionsAllowed":False,"dataQualitySummary":{"status":"synthetic evidence accepted"},"consensusSummary":{"status":"synthetic agreement evaluated"},"sersAdvisory":{"riskBand":"WATCH","advisoryOnly":True},"humanReviewRequired":True,"blockedActions":["release","quarantine","discard","reroute","customer messaging"],"evidenceRoutes":["/data-quality","/consensus","/sers","/reviewer-workspace"]}

